import React from "react";
import Sidebar from "./Sidebar";

export default function Layout({ children }) {
  return (
    <div style={{ display: "flex" }}>
      <Sidebar />

      <div
        style={{
          marginLeft: "250px",
          padding: "20px",
          width: "100%",
          minHeight: "100vh",
          background: "#f8f9fa",
        }}
      >
        {children}
      </div>
    </div>
  );
}
